package blue.contract.processor.conversation.javascript.chicory;

public final class HostV1Manifest {
    public static final String ABI_ID = "Host.v1";
    public static final int ABI_VERSION = 1;
    public static final String HOST_V1_HASH =
            "e23b0b2ee169900bbde7aff78e6ce20fead1715c60f8a8e3106d9959450a3d34";
    public static final String HOST_V1_BYTES_HEX =
            "";

    public static final int DOCUMENT_GET_FN_ID = 1;
    public static final int DOCUMENT_GET_CANONICAL_FN_ID = 2;
    public static final int EMIT_FN_ID = 3;

    private HostV1Manifest() {
    }

    public static byte[] bytes() {
        return hexToBytes(HOST_V1_BYTES_HEX);
    }

    private static byte[] hexToBytes(String hex) {
        if ((hex.length() & 1) != 0) {
            throw new IllegalArgumentException("hex string must have even length");
        }
        byte[] bytes = new byte[hex.length() / 2];
        for (int i = 0; i < bytes.length; i++) {
            int high = Character.digit(hex.charAt(i * 2), 16);
            int low = Character.digit(hex.charAt(i * 2 + 1), 16);
            if (high < 0 || low < 0) {
                throw new IllegalArgumentException("invalid hex at byte " + i);
            }
            bytes[i] = (byte) ((high << 4) | low);
        }
        return bytes;
    }
}
